{
  "executive_summary": "Design a unified API gateway architecture for a logistics platform serving three consumer tiers (mobile, B2B partner, internal). The gateway centralizes authentication, rate limiting, and traffic isolation — replacing the current inconsistent per-service implementations. The architecture uses a single gateway with distinct listener/route groups per consumer type, an anti-corruption layer to shield internal services, and a plugin-based pipeline for cross-cutting concerns.",

  "architecture": {
    "components": [
      {
        "name": "Edge Gateway",
        "responsibility": "Single entry point for all external traffic (mobile + B2B). Terminates TLS, performs initial request validation, routes to correct authentication pipeline based on consumer type detection (path prefix or host header).",
        "boundaries": "Handles ONLY external traffic. Never processes internal service-to-service calls. Stateless — all session/token state lives in external stores."
      },
      {
        "name": "Authentication Pipeline",
        "responsibility": "Two parallel auth strategies: (1) JWT/OAuth2 validation for mobile consumers against Identity Provider, (2) API key validation + HMAC signature verification for B2B partners against Partner Registry. Emits a normalized internal identity token downstream.",
        "boundaries": "Auth decisions only. No business logic. No rate limiting. Produces a canonical identity envelope (consumer_type, consumer_id, tier, permissions) attached to the request context."
      },
      {
        "name": "Rate Limiter",
        "responsibility": "Enforces per-consumer rate limits using a sliding window algorithm backed by Redis. Mobile: 100 req/min keyed by user_id. B2B: 1,000 req/min keyed by partner_id. Returns 429 with Retry-After header on breach.",
        "boundaries": "Stateless process, external state in Redis. Does not make auth decisions — relies on identity envelope from auth pipeline. Rate limit configs are externalized (not hardcoded)."
      },
      {
        "name": "Internal Gateway (Service Mesh Sidecar)",
        "responsibility": "Handles internal service-to-service communication. No authentication required. Provides service discovery, circuit breaking, retries, and observability. Runs on a separate network interface / port that is NOT reachable from the public internet.",
        "boundaries": "Physically isolated from edge gateway. Bound to internal network only (e.g., private subnet, localhost, or mesh overlay). No TLS termination from external clients."
      },
      {
        "name": "Webhook Dispatcher",
        "responsibility": "Asynchronous delivery of webhook events to B2B partners. Consumes domain events from an internal event bus, formats payloads per partner contract, delivers with exponential backoff retry (max 5 attempts), and logs delivery status.",
        "boundaries": "Outbound only — never receives inbound traffic. Owns its own delivery queue and retry state. Partners register webhook URLs via Partner Registry."
      },
      {
        "name": "Partner Registry",
        "responsibility": "Stores B2B partner configurations: API keys, webhook URLs, rate limit overrides, allowed scopes. Serves as the source of truth for partner identity and entitlements.",
        "boundaries": "Internal service only. Not exposed externally. Accessed by Auth Pipeline and Webhook Dispatcher."
      },
      {
        "name": "Identity Provider",
        "responsibility": "Issues and validates JWT tokens for mobile consumers. Handles login, token refresh, and revocation. Existing service — gateway delegates to it, does not replace it.",
        "boundaries": "Owned by the identity/auth team. Gateway treats it as an external dependency with circuit breaker protection."
      }
    ],
    "interfaces": [
      {
        "from": "Mobile App",
        "to": "Edge Gateway",
        "contract": "HTTPS requests with Bearer JWT in Authorization header. Path prefix: /api/v1/customer/*",
        "coupling_type": "loose — standard HTTP + JWT, no proprietary protocol"
      },
      {
        "from": "B2B Partner",
        "to": "Edge Gateway",
        "contract": "HTTPS requests with X-API-Key header + HMAC signature in X-Signature header. Path prefix: /api/v1/partner/*",
        "coupling_type": "loose — standard HTTP + API key, webhook contract defined by Published Language (JSON Schema)"
      },
      {
        "from": "Edge Gateway",
        "to": "Authentication Pipeline",
        "contract": "Internal function call / middleware chain. Input: raw request. Output: identity envelope {consumer_type, consumer_id, tier, permissions} or 401 rejection.",
        "coupling_type": "tight — in-process middleware pipeline, but strategy pattern allows swapping auth mechanisms"
      },
      {
        "from": "Edge Gateway",
        "to": "Rate Limiter",
        "contract": "Internal middleware call. Input: identity envelope + request metadata. Output: pass-through or 429 response. Reads limits from config keyed by (consumer_type, consumer_id).",
        "coupling_type": "tight — in-process, but rate limit configs are externalized"
      },
      {
        "from": "Edge Gateway",
        "to": "Backend Services",
        "contract": "HTTP/gRPC with X-Consumer-Type, X-Consumer-Id, X-Request-Id headers injected by gateway. Backend services MUST NOT trust raw auth headers — only gateway-injected identity headers.",
        "coupling_type": "loose — backend services are auth-unaware, they trust the gateway's identity headers"
      },
      {
        "from": "Internal Services",
        "to": "Internal Gateway",
        "contract": "HTTP/gRPC on internal network (port 8081 or mesh overlay). No auth headers. X-Request-Id for tracing. mTLS optional for defense-in-depth.",
        "coupling_type": "loose — service mesh provides discovery and routing transparently"
      },
      {
        "from": "Backend Services",
        "to": "Webhook Dispatcher",
        "contract": "Domain events published to event bus (e.g., order.shipped, delivery.completed). Dispatcher subscribes and maps events to partner webhook payloads.",
        "coupling_type": "very loose — async event-driven, no direct coupling between services and dispatcher"
      },
      {
        "from": "Webhook Dispatcher",
        "to": "B2B Partner",
        "contract": "POST to registered webhook URL with JSON payload, HMAC signature in X-Webhook-Signature header for verification. Partner must return 2xx within 10s.",
        "coupling_type": "loose — standard webhook contract, partner owns their endpoint"
      }
    ],
    "data_flow": "External request → Edge Gateway (TLS termination) → Consumer Type Detection (path/host routing) → Authentication Pipeline (JWT or API key validation → normalized identity envelope) → Rate Limiter (sliding window check against Redis) → Request Transformation (strip external auth headers, inject internal identity headers + request ID) → Route to Backend Service. For webhooks: Backend Service emits domain event → Event Bus → Webhook Dispatcher → Retry Queue → Partner Endpoint. Internal service-to-service: Service A → Internal Gateway/Mesh (separate network) → Service B. Key invariant: external and internal traffic NEVER share the same network path.",
    "patterns_used": [
      {
        "pattern": "API Gateway (Edge)",
        "rationale": "Centralizes cross-cutting concerns (auth, rate limiting, routing) that are currently duplicated inconsistently across services. Single point of policy enforcement eliminates the class of bugs where one service has weaker auth than another."
      },
      {
        "pattern": "Strategy Pattern for Authentication",
        "rationale": "Mobile (JWT) and B2B (API key + HMAC) require fundamentally different auth flows. Strategy pattern lets the gateway select the correct authenticator based on consumer type detection, keeping each strategy simple and independently testable."
      },
      {
        "pattern": "Middleware Pipeline",
        "rationale": "Auth → Rate Limit → Transform → Route is a natural pipeline. Each stage is a composable middleware that can be independently tested, reordered, or extended (e.g., adding request logging or WAF rules later)."
      },
      {
        "pattern": "Network-Level Isolation (Internal vs External)",
        "rationale": "Internal services must be unreachable from external traffic. Rather than relying on software-level checks (which can have bugs), physical network isolation (separate listener, separate subnet) provides defense-in-depth."
      },
      {
        "pattern": "Sliding Window Rate Limiting",
        "rationale": "More accurate than fixed window (avoids burst-at-boundary problem) and more memory-efficient than token bucket for the given scale. Redis-backed for horizontal scalability of gateway instances."
      },
      {
        "pattern": "Async Webhook Delivery with Retry Queue",
        "rationale": "Webhooks to partner endpoints are inherently unreliable (partner downtime, network issues). Decoupling via event bus + retry queue ensures backend services are not blocked by webhook delivery and partners eventually receive all events."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "API Access Control",
        "classification": "supporting",
        "aggregates": ["ConsumerIdentity (type, id, tier, permissions)", "RateLimitPolicy (consumer_type, limit, window, current_count)"]
      },
      {
        "name": "Partner Management",
        "classification": "supporting",
        "aggregates": ["Partner (id, api_key_hash, webhook_urls, rate_limit_override, allowed_scopes)", "WebhookSubscription (partner_id, event_types, target_url, secret)"]
      },
      {
        "name": "Customer Identity",
        "classification": "generic",
        "aggregates": ["User (id, credentials, tokens) — existing IdP, treat as external"]
      },
      {
        "name": "Logistics Core",
        "classification": "core",
        "aggregates": ["Order", "Shipment", "Delivery — these are downstream consumers of the gateway, not designed here"]
      }
    ],
    "context_map": [
      {
        "upstream": "Customer Identity (IdP)",
        "downstream": "API Access Control (Gateway)",
        "relationship": "Conformist — gateway conforms to IdP's JWT format and validation rules. Gateway does not dictate token structure."
      },
      {
        "upstream": "Partner Management",
        "downstream": "API Access Control (Gateway)",
        "relationship": "Customer-Supplier — Partner Registry supplies API key validation data and rate limit configs to the gateway. Gateway is the customer."
      },
      {
        "upstream": "Logistics Core",
        "downstream": "Partner Management (Webhook Dispatcher)",
        "relationship": "Published Language — Core domain publishes domain events in a stable schema. Webhook Dispatcher translates to partner-facing payload format via ACL."
      }
    ]
  },

  "trade_offs": [
    {
      "decision": "Single edge gateway vs separate gateways per consumer type",
      "gains": "One deployment to manage, shared infrastructure (TLS, observability, health checks), simpler ops. Consumer isolation achieved via routing rules and middleware composition, not separate processes.",
      "sacrifices": "A misconfiguration or crash affects all consumer types simultaneously. Blast radius is larger than separate gateways.",
      "alternatives_considered": [
        "Separate gateway per consumer type — better isolation but 3x ops burden, harder to keep consistent",
        "BFF (Backend for Frontend) per consumer — overkill at this stage, warranted only if consumer-specific aggregation logic emerges"
      ]
    },
    {
      "decision": "Redis-backed sliding window rate limiter vs in-process token bucket",
      "gains": "Horizontally scalable (multiple gateway instances share rate limit state). Accurate limits across all instances. Survives gateway restarts.",
      "sacrifices": "Adds Redis as a critical dependency. If Redis is down, must decide: fail-open (allow all traffic, risk abuse) or fail-closed (reject all traffic, cause outage).",
      "alternatives_considered": [
        "In-process token bucket — simpler, no Redis dependency, but limits are per-instance not per-consumer when running multiple gateway replicas",
        "Distributed token bucket (e.g., Resilience4j + Hazelcast) — more complex than Redis sliding window for minimal benefit"
      ]
    },
    {
      "decision": "Network-level isolation for internal services vs software-level ACL",
      "gains": "Defense-in-depth. Even if gateway has a bug, internal services are unreachable from the internet. Zero-trust at the network layer.",
      "sacrifices": "Requires network infrastructure support (separate subnets, firewall rules, or service mesh). More complex deployment topology.",
      "alternatives_considered": [
        "Software-only isolation (reject requests without internal header) — simpler but one bug away from exposing internal services",
        "VPN for internal traffic — heavy-handed, adds latency, operational burden"
      ]
    },
    {
      "decision": "Async webhook delivery via event bus vs synchronous callback from gateway",
      "gains": "Backend services are decoupled from webhook delivery. Failed deliveries don't block request processing. Natural retry semantics.",
      "sacrifices": "Eventual consistency — partners don't get instant notification. Adds event bus as infrastructure dependency.",
      "alternatives_considered": [
        "Synchronous webhook from gateway — simpler but blocks request, couples availability to partner endpoint health",
        "Polling API instead of webhooks — simpler to build but worse partner experience, higher load from polling"
      ]
    }
  ],

  "flexibility_points": [
    {
      "area": "Authentication strategies",
      "evolution_path": "Strategy pattern means adding a third consumer type (e.g., OAuth2 for marketplace sellers) requires only a new authenticator implementation and a routing rule — no changes to existing strategies."
    },
    {
      "area": "Rate limit policies",
      "evolution_path": "Externalized rate limit configs (not hardcoded). Can evolve to dynamic tiering (e.g., premium partners get 5,000 req/min) by updating Partner Registry without gateway redeployment."
    },
    {
      "area": "Middleware pipeline",
      "evolution_path": "New cross-cutting concerns (WAF, request logging, A/B routing, canary deployments) are added as new middleware stages. Pipeline is composable and order-configurable."
    },
    {
      "area": "Webhook event types",
      "evolution_path": "Adding new webhook events requires only: (1) core domain publishes new event, (2) dispatcher adds mapping. No partner-facing API changes needed."
    }
  ],

  "rigidity_points": [
    {
      "area": "Gateway as single entry point for external traffic",
      "reason": "ALL external requests MUST flow through the edge gateway. Services must NOT expose public endpoints directly. This rigidity is intentional — it's the security invariant that makes centralized auth trustworthy. Bypass = vulnerability."
    },
    {
      "area": "Identity envelope contract (X-Consumer-Type, X-Consumer-Id headers)",
      "reason": "Backend services depend on this internal header contract. Changing it requires coordinated updates across all services. Keep it stable and versioned. This is the 'shared kernel' between gateway and backends."
    },
    {
      "area": "Network isolation boundary",
      "reason": "Internal services must remain unreachable from public internet. This is a non-negotiable security boundary. Moving a service from internal to external requires explicit gateway route + auth configuration."
    }
  ],

  "risks": [
    {
      "risk": "Gateway becomes a single point of failure — all external traffic dies if gateway is down",
      "severity": "critical",
      "mitigation": "Deploy gateway as a horizontally scaled, stateless cluster behind a load balancer. Health checks with automatic instance replacement. Target 99.99% availability. Redis failure mode: fail-open with alerting (allow traffic but log rate limit bypass)."
    },
    {
      "risk": "Migration from per-service auth to centralized gateway auth causes outages during transition",
      "severity": "high",
      "mitigation": "Phased rollout: (1) Deploy gateway in shadow mode (logs decisions but doesn't enforce), (2) Route one low-risk service through gateway, (3) Gradually migrate remaining services. Keep per-service auth as fallback during migration. Feature flag per service."
    },
    {
      "risk": "Redis rate limiter failure causes either abuse (fail-open) or outage (fail-closed)",
      "severity": "high",
      "mitigation": "Default to fail-open with degraded-mode alerting. Use Redis Sentinel or Cluster for HA. Implement local in-process rate limiter as fallback (less accurate but functional). Monitor rate limit bypass events."
    },
    {
      "risk": "Webhook delivery to unreliable partner endpoints causes queue backlog and resource exhaustion",
      "severity": "medium",
      "mitigation": "Exponential backoff with max 5 retries and dead-letter queue. Per-partner circuit breaker — if a partner endpoint fails repeatedly, stop attempting delivery and alert. Queue size monitoring with alerting thresholds."
    },
    {
      "risk": "Internal identity headers (X-Consumer-Type, X-Consumer-Id) can be spoofed if a service is accidentally exposed publicly",
      "severity": "medium",
      "mitigation": "Gateway MUST strip all X-Consumer-* headers from incoming requests before injecting its own. Backend services should validate that requests come from known internal IPs/mesh. Defense-in-depth: even if headers are trusted, network isolation prevents external access."
    }
  ],

  "implementation_guidance": {
    "recommended_approach": "Start with a proven API gateway framework (Kong, Envoy, or cloud-native like AWS API Gateway + ALB) rather than building from scratch. Phase 1: Deploy gateway with mobile JWT auth + rate limiting for a single non-critical service. Phase 2: Add B2B API key auth + partner rate limits, migrate remaining services. Phase 3: Add webhook dispatcher. Phase 4: Remove per-service auth code (only after gateway is proven stable). Estimated Phase 1 timeline: 2-3 weeks including shadow mode validation.",
    "files_to_create_or_modify": [
      "gateway/config/routes.yaml — route definitions mapping path prefixes to backend services and consumer types",
      "gateway/middleware/auth/jwt_authenticator.ts — JWT validation strategy for mobile consumers",
      "gateway/middleware/auth/apikey_authenticator.ts — API key + HMAC validation strategy for B2B partners",
      "gateway/middleware/auth/identity_envelope.ts — canonical identity type and header injection logic",
      "gateway/middleware/rate_limiter.ts — sliding window rate limiter with Redis backend and fail-open fallback",
      "gateway/middleware/header_sanitizer.ts — strips untrusted headers from incoming requests before auth pipeline",
      "services/partner-registry/src/models/partner.ts — partner entity with API key hash, webhook config, rate limit override",
      "services/webhook-dispatcher/src/dispatcher.ts — event consumer that formats and delivers webhooks with retry",
      "services/webhook-dispatcher/src/retry_queue.ts — exponential backoff retry with dead-letter queue",
      "infra/network/internal-gateway.yaml — network policy / firewall rules isolating internal services from external traffic"
    ],
    "patterns_to_follow": "Middleware pipeline for request processing (auth → rate limit → transform → route). Strategy pattern for auth (interface Authenticator { authenticate(req): IdentityEnvelope | Rejection }). Externalized configuration for rate limits and routing rules. Circuit breaker on all outbound calls (to IdP, Redis, backend services, partner webhooks). Structured logging with correlation IDs (X-Request-Id) propagated through the entire chain.",
    "pitfalls_to_avoid": [
      "Do NOT build a custom gateway from scratch — use a proven framework and customize via plugins/middleware",
      "Do NOT do a big-bang migration — phase services through the gateway one at a time with shadow mode first",
      "Do NOT hardcode rate limits — externalize to config so they can be tuned without redeployment",
      "Do NOT let backend services keep their own auth logic after migration — dual auth creates confusion about which is authoritative",
      "Do NOT trust any headers from external requests — the gateway must sanitize ALL internal headers before injecting its own",
      "Do NOT use a shared Redis instance for rate limiting and application caching — a cache stampede should not take down rate limiting",
      "Do NOT skip the fail-open fallback for rate limiting — Redis downtime should degrade gracefully, not cause a full outage"
    ]
  },

  "escalations": [],

  "confidence": {
    "level": 85,
    "high_confidence_areas": [
      "Gateway middleware pipeline design — well-established pattern with proven implementations",
      "Network isolation for internal services — standard security practice",
      "Auth strategy separation (JWT vs API key) — clear consumer type distinction makes this straightforward",
      "Async webhook delivery with retry — standard pattern for unreliable outbound delivery"
    ],
    "low_confidence_areas": [
      "Specific gateway technology choice (Kong vs Envoy vs cloud-native) — depends on team's infrastructure stack and expertise, which is unknown",
      "Exact Redis topology for rate limiting — depends on scale (total request volume unknown), could be overkill or underkill",
      "Internal service mesh specifics — depends on whether team uses Kubernetes, bare metal, or cloud-managed services"
    ],
    "assumptions": [
      "Team has infrastructure to deploy a horizontally scaled stateless service (load balancer, health checks)",
      "Redis or equivalent is available or can be provisioned for rate limit state",
      "Internal services are on a separate network segment or can be isolated via firewall rules",
      "Existing Identity Provider issues standard JWTs that can be validated without calling the IdP on every request (public key / JWKS)",
      "Request volume is moderate enough that a single gateway cluster (with horizontal scaling) is sufficient — no need for geographic distribution yet"
    ]
  }
}

